import{_ as r,o as i,c as t,a2 as s}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Logistique & Technique","description":"","frontmatter":{"title":"Logistique & Technique"},"headers":[],"relativePath":"docs/fr/faq/logistics-tech.md","filePath":"docs/fr/faq/logistics-tech.md"}'),o={name:"docs/fr/faq/logistics-tech.md"};function a(d,e,n,l,p,u){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="logistique-print-technique" tabindex="-1">Logistique, Print &amp; Technique <a class="header-anchor" href="#logistique-print-technique" aria-label="Permalink to &quot;Logistique, Print &amp; Technique&quot;">​</a></h1><h2 class="text-red-200">🚨 Dépannage Technique (Urgent)</h2><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Mon QR Code renvoie vers une page 404</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"><strong>Cause probable :</strong> L&#39;URL de destination configurée dans la plateforme est vide ou erronée.<br><strong>Solution :</strong><ol><li>Connectez-vous à <a href="https://app.getinside.media">app.getinside.media</a>.</li><li>Allez dans la campagne concernée &gt; Onglet <em>Configuration</em>.</li><li>Vérifiez le champ &quot;URL de redirection&quot;.</li><li>Sauvegardez. La mise à jour est <strong>instantanée</strong> (pas besoin de réimprimer).</li></ol></div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Je n&#39;arrive pas à booster le post Instagram</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"><strong>Cause :</strong> L&#39;éditeur n&#39;a pas coché la bonne case.<br><strong>Solution pour l&#39;Éditeur :</strong><ol><li>Aller sur le post Instagram &gt; 3 points &gt; Modifier.</li><li>Vérifier que le label &quot;Partenariat rémunéré&quot; est actif.</li><li>Vérifier que l&#39;option <strong>&quot;Autoriser le partenaire de marque à booster&quot;</strong> est active.</li></ol></div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">L&#39;image de ma newsletter ne s&#39;affiche pas</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"><strong>Cause :</strong> Problème d&#39;hébergement ou de lien.<br><strong>Solution pour l&#39;Éditeur :</strong><ul><li>Le lien de l&#39;image est-il en <code>https</code> ? (Obligatoire).</li><li>L&#39;image est-elle hébergée sur un serveur public ?</li><li>Avez-vous respecté le poids max (150ko) ?</li></ul><em>Test : Ouvrez l&#39;URL de l&#39;image seule dans un navigateur privé. Si elle ne charge pas, le problème vient de l&#39;hébergement.</em></div></details><br><h2>📦 Gestion Logistique</h2><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">J&#39;ai reçu les encarts en avance, puis-je commencer ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Il faut impérativement le feu vert de l&#39;annonceur pour diffuser une campagne plus tôt que prévu. Cela peut être gênant si la campagne entre en concurrence avec une autre offre ou si la landing page n&#39;est pas encore active. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Les flyers sont arrivés endommagés</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"><strong>Action immédiate requise (sous 24h) :</strong><ol><li>Prenez des photos claires des cartons abîmés.</li><li>Notez des réserves précises sur le bon de livraison (BL).</li><li>Envoyez le tout à <code>logistique@getinside.fr</code>.</li></ol><strong>Ne distribuez pas</strong> les supports endommagés. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Écart de stock (J&#39;ai reçu plus ou moins de flyers que prévu)</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"><strong>Cas 1 : Vous en avez reçu MOINS</strong><br> Signalez-le immédiatement à l&#39;annonceur et à getinside via la messagerie de la campagne. <br><br><strong>Cas 2 : Vous en avez reçu PLUS (Surplus)</strong><br> C&#39;est normal. Ce surplus correspond à la <strong>tolérance de passe (± 5%)</strong> prévue par l&#39;industrie graphique. <ul><li><strong>Facturation :</strong> Le budget reste celui validé initialement.</li><li><strong>Action :</strong> Idéalement, écoulez ce surplus. Sinon, arrêtez la distribution une fois la quantité commandée atteinte.</li></ul></div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Standards RSE et Impression</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Nos partenaires imprimeurs sont certifiés <strong>Imprim&#39;vert</strong>, ISO 9001/14001 et utilisent du papier FSC. L&#39;assemblage manuel (ex: échantillons) est réalisé par des <strong>Entreprises Adaptées (EA)</strong> favorisant l&#39;emploi de travailleurs handicapés. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Puis-je utiliser le service d&#39;impression pour mes propres besoins ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Absolument. En tant que centrale d&#39;achat, nous faisons bénéficier tous nos membres de tarifs négociés. Que ce soit pour de l&#39;auto-promotion ou des besoins internes, nous pouvons gérer l&#39;impression et les demandes spéciales. </div></details><br><h2>🎨 Création &amp; Tracking</h2><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Est-ce que getinside peut créer mes visuels ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Oui. Notre <strong>Studio Créatif</strong> peut réaliser vos flyers, emails ou bannières pour un forfait de <strong>550€ HT</strong> par campagne. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment tracker les ventes (ROI) ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> getinside ne place pas de pixel sur votre site. L&#39;attribution repose sur deux leviers :<br> 1. <strong>Code Promo Unique :</strong> Créez un code spécifique (ex: <code>MERCI20</code>).<br> 2. <strong>Liens UTM :</strong> Configurez l&#39;URL de votre QR Code avec des paramètres UTM (ex: <code>utm_source=asile-colis</code>) pour suivre le trafic dans Google Analytics. </div></details>',16)])])}const c=r(o,[["render",a]]);export{g as __pageData,c as default};
